def coerce_schema(raw, schema, nullable=None):
    nullable = nullable or set()
    result = {}
    for field, pair in schema.items():
        caster, default = pair
        candidate = raw[field] if field in raw else default
        if field in nullable and field in raw and candidate is None:
            result[field] = None
            continue
        try:
            result[field] = caster(candidate)
        except Exception as exc:
            raise ValueError(f'bad field: {field}') from exc
    return result

